from bs4 import BeautifulSoup as soup


def validateXmlFile(data):
    souped = soup(
        data, features="lxml", from_encoding='ISO-8859-1')

    error_message = "The XML is not valid. Please, make sure it is in XML format."

    try: 
        root = souped.xml["name"] 
        print("XML valid!")
    except Exception as e :
        print(error_message)